209	func evaluateOpenLifecycleQueue(f LifecycleQueueFacts, decision LifecycleQueueDecision) LifecycleQueueDecision {
210		if !decision.DependenciesSatisfied {
211			decision.Bucket = LifecycleBucketWaitingDependencies
212			return decision
213		}
214		if strings.TrimSpace(f.SupersededBy) != "" {
215			decision.Bucket = LifecycleBucketSuperseded
216			return decision
217		}
218		if f.EpicContainer {
219			decision.Bucket = LifecycleBucketEpicContainer
220			return decision
221		}
222		if f.RetryCooldownActive {
223			decision.Bucket = LifecycleBucketRetryCooldown
224			return decision
225		}
226		if f.ExecutionEligibleKnown && !f.ExecutionEligible {
227			decision.Bucket = LifecycleBucketNotEligible
228			return decision
229		}
230		decision.Bucket = LifecycleBucketReady
231		decision.WorkerEligible = true
232		return decision
233	}
